"use client";
import { cn } from "@/lib/utils";
import React from "react";

// nextjs-icon-library.tsx
// A single-file SVG icon system for Next.js + React (TypeScript)
// - Export individual icons (tree-shakable)
// - Default <Icon name="..." /> wrapper for dynamic name-based rendering
// - Accessible: supports title/desc and aria-hidden
// - Flexible size, strokeWidth, viewBox, className

export type IconCommonProps = React.SVGProps<SVGSVGElement> & {
  size?: number | string; // e.g. 16 or "1.5rem"
  strokeWidth?: number;
  title?: string | null; // accessibility title
  decorative?: boolean; // if true, aria-hidden=true
};

const normalizeSize = (size?: number | string) =>
  size === undefined ? 24 : typeof size === "number" ? `${size}px` : size;

// ----------------------
// Individual SVG icons
// ----------------------
// Keep each icon as a named export so bundlers can tree-shake unused icons.

