const icons = {
  user: UserCircleIcon,
  heart: HeartIcon,
  home: HomeIcon,
  bag: BagIcon,
  verifiedIcon: ShieldCheckIcon,
  search: SearchIcon,
  newIcon: NewIcon,
} as const;

export type IconName = keyof typeof icons;

export const Icon = ({
  name,
  size = 24,
  strokeWidth,
  title,
  decorative = false,
  className,
  ...props
}: { name: IconName } & IconCommonProps) => {
  const IconComponent = icons[name];
  // Render the specific icon component with props
  return (
    <IconComponent
      size={size}
      strokeWidth={strokeWidth}
      title={title}
      decorative={decorative}
      className={className}
      {...props}
    />
  );
};

